import{_ as t,Z as e,P as l,g as r,k as i,m as a}from"./chunks/framework.Dp5g00Bf.js";const v=JSON.parse('{"title":"vscode配置备份","description":"","frontmatter":{},"headers":[],"relativePath":"views/1-开发🌏/3-运维/vscode配置备份/index.md","filePath":"views/1-开发🌏/3-运维/vscode配置备份/index.md","lastUpdated":1778336291000}'),p={name:"views/1-开发🌏/3-运维/vscode配置备份/index.md"};function c(d,s,b,u,h,g){const n=e("NolebaseGitContributors"),o=e("NolebaseGitChangelog");return l(),r("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1778336291000"},[s[0]||(s[0]=i(`<h1 id="vscode配置备份" tabindex="-1">vscode配置备份 <a class="header-anchor" href="#vscode配置备份" aria-label="Permalink to &quot;vscode配置备份&quot;">​</a></h1><p>按照以下步骤操作即可：</p><h3 id="第一步-打开配置文件" tabindex="-1">第一步：打开配置文件 <a class="header-anchor" href="#第一步-打开配置文件" aria-label="Permalink to &quot;第一步：打开配置文件&quot;">​</a></h3><p>在 VS Code 中按下 <code>Ctrl+Shift+P</code> (macOS 为 <code>Cmd+Shift+P</code>)，输入并选择：</p><blockquote><p><code>Sync Settings: Open the repository settings</code></p></blockquote><p>这会为你打开一个名为 <code>settings.yml</code> 的文件。</p><hr><h3 id="第二步-修改-webdav-配置" tabindex="-1">第二步：修改 WebDAV 配置 <a class="header-anchor" href="#第二步-修改-webdav-配置" aria-label="Permalink to &quot;第二步：修改 WebDAV 配置&quot;">​</a></h3><p>将文件中的内容替换（或修改）为以下模板，请根据你的 WebDAV 服务（如坚果云、Nextcloud、Alist 等）填写具体信息：</p><p><strong>YAML</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># 选定的配置文件名称，默认叫 main 即可</span></span>
<span class="line"><span>profile: main</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 仓库配置</span></span>
<span class="line"><span>repository:</span></span>
<span class="line"><span>  type: webdav</span></span>
<span class="line"><span>  # 你的 WebDAV 连接地址（末尾建议加上专用目录，如 /vscode/）</span></span>
<span class="line"><span>  url: http://你的服务器地址/webdav/vscode/</span></span>
<span class="line"><span>  # 账号</span></span>
<span class="line"><span>  username: your_username</span></span>
<span class="line"><span>  # 密码（建议使用 WebDAV 服务生成的“应用专用密码”）</span></span>
<span class="line"><span>  password: your_password</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><p><strong>注意：</strong> 如果你的 WebDAV 开启了 HTTPS，请确保 URL 以 <code>https://</code> 开头。</p><hr><h3 id="第三步-上传你的配置-初次使用" tabindex="-1">第三步：上传你的配置（初次使用） <a class="header-anchor" href="#第三步-上传你的配置-初次使用" aria-label="Permalink to &quot;第三步：上传你的配置（初次使用）&quot;">​</a></h3><p>配置好 YAML 文件后，再次按下 <code>Ctrl+Shift+P</code>，执行：</p><blockquote><p><code>Sync Settings: Upload (user -&gt; repository)</code></p></blockquote><p>此时，插件会将你当前的 <strong>设置、快捷键、代码片段、插件列表</strong> 上传到你的 WebDAV 服务器。你可以去网盘里看看是不是多了很多 JSON 文件。</p><hr><h3 id="第四步-在其他设备下载" tabindex="-1">第四步：在其他设备下载 <a class="header-anchor" href="#第四步-在其他设备下载" aria-label="Permalink to &quot;第四步：在其他设备下载&quot;">​</a></h3><p>在第二台电脑上安装好 VS Code 和该插件后：</p><ol><li>重复<strong>第一步</strong>和 <strong>第二步</strong> （填入相同的 WebDAV 地址和账号）。</li><li>按下 <code>Ctrl+Shift+P</code>，执行： <blockquote><p><code>Sync Settings: Download (repository -&gt; user)</code></p></blockquote></li><li>VS Code 会自动开始下载配置并静默安装你列表中的插件。</li></ol><hr><h3 id="进阶技巧-哪些东西会被同步" tabindex="-1">进阶技巧：哪些东西会被同步？ <a class="header-anchor" href="#进阶技巧-哪些东西会被同步" aria-label="Permalink to &quot;进阶技巧：哪些东西会被同步？&quot;">​</a></h3><p>默认情况下，它会同步绝大多数内容。如果你想自定义，可以在 VS Code 的常规设置 <code>settings.json</code> 中添加：</p><ul><li><strong>排除特定插件：</strong> <code>&quot;syncSettings.ignoredExtensions&quot;: [&quot;某些不想同步的插件ID&quot;]</code></li><li><strong>同步额外的文件：</strong> 如果你有些特殊的配置文件（比如某个插件的数据库文件）在别处，可以用 <code>syncSettings.additionalFiles</code> 来指定。</li><li><strong>多系统适配：</strong> 如果你在 Windows 和 Mac 之间同步，由于字体或路径不同，可以利用文档中提到的 <code>// #if(os=&quot;mac&quot;)</code> 这种注释语法来写 <code>settings.json</code>。</li></ul><h3 id="常见问题排查" tabindex="-1">常见问题排查 <a class="header-anchor" href="#常见问题排查" aria-label="Permalink to &quot;常见问题排查&quot;">​</a></h3><ul><li><strong>上传失败：</strong> 请检查 WebDAV 的 URL 路径是否存在。有些服务要求你必须手动先在网盘里创建一个叫 <code>vscode</code> 的文件夹。</li><li><strong>密码报错：</strong> 如果你使用的是坚果云等服务，必须在后台开启 WebDAV 并生成 <strong>专用密码</strong> ，直接用登录密码通常会失败。</li></ul>`,27)),a(n),a(o)])}const _=t(p,[["render",c]]);export{v as __pageData,_ as default};
